/**
 * Scope hit-test — pure snap-to-nearest-trace over a projected Frame.
 *
 * Given a pointer position in canvas coordinates and a Frame, return the
 * HoverSelection identifying the nearest trace within HOVER_SNAP_DISTANCE_PX
 * vertically at the pointer's x-time, or `null` when no trace is close enough.
 *
 * Geometry contract (matches the canvas coordinate system used by the scope):
 *   - timeToX(t, width, now) = width * (1 - (now - t) / WINDOW_MS)
 *     (older-left, newer-right; the newest sample sits at x = width)
 *   - valueToY(v, height, yMax) = height * (1 - v / yMax)
 *     (low-value-bottom, high-value-top; canvas origin is top-left)
 *
 * Algorithm:
 *   1. Reject pointers outside [0, width] x [0, height].
 *   2. Convert pointer.x to a cursor-time via the inverse of timeToX.
 *   3. For each trace, find the sample whose time is nearest the cursor-time
 *      (this is the column the pointer is over).
 *   4. Compute the trace's displayY at that sample. An off-canvas sample
 *      (value above yMax, or negative) is visually clipped to the nearest
 *      canvas edge — its effective distance to a pointer inside the canvas
 *      is measured to the clipped edge, so off-scale traces remain hoverable
 *      anywhere at that x-time (a design choice mirroring the scope's visual
 *      clipping behavior).
 *   5. Pick the trace whose vertical distance is minimum; return null if that
 *      distance exceeds HOVER_SNAP_DISTANCE_PX.
 *
 * Pure: no imports from `react`, `adapters`, `views`, `window`, `document`,
 * or `domain/oscilloscope`. Inspects only the Frame structure and the
 * HOVER_SNAP_DISTANCE_PX constant.
 */

import { WINDOW_MS } from "./phosphorMetricConfig";
import type { Frame, FrameTrace } from "./scopeProjection";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/**
 * Maximum pixel distance for snap-to-trace hover. Sourced from the prototype
 * spec (28px ≈ thumb-width on a high-DPI laptop display, comfortable for
 * pointer targeting without feeling sticky).
 */
export const HOVER_SNAP_DISTANCE_PX = 28;

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

export interface PointerPosition {
  readonly x: number;
  readonly y: number;
  readonly width: number;
  readonly height: number;
}

export interface HoverSelection {
  readonly sessionId: string;
  readonly color: string;
  readonly value: number;
  readonly time: number;
  readonly ageMs: number;
  readonly displayX: number;
  readonly displayY: number;
}

// ---------------------------------------------------------------------------
// Pure geometry helpers — mirror the canvas host's projection math
// ---------------------------------------------------------------------------

/** Map a sample time `t` to x pixels within `[0, width]` given `now`. */
const timeToX = (t: number, width: number, now: number): number =>
  width * (1 - (now - t) / WINDOW_MS);

/** Inverse of timeToX: map a pointer x to a cursor-time given `now`. */
const xToTime = (x: number, width: number, now: number): number =>
  now - (1 - x / width) * WINDOW_MS;

/** Map a sample value `v` to y pixels within `[0, height]` given `yMax`. */
const valueToY = (v: number, height: number, yMax: number): number =>
  height * (1 - v / yMax);

/**
 * Whether a sample's displayY falls outside the visible canvas (above the
 * top, i.e. displayY < 0, or below the bottom, i.e. displayY > height).
 * Off-canvas samples are visually clipped; the scope still renders them at
 * the edge, so the user can hover anywhere in the canvas at that x-time
 * and expect to select this trace.
 */
const isSampleOffCanvas = (sampleY: number, height: number): boolean =>
  sampleY < 0 || sampleY > height;

/**
 * Effective vertical distance from the pointer to a trace sample's visible
 * rendering. On-canvas samples: absolute y-difference. Off-canvas samples:
 * zero — the trace is clipped to the viewport so the user selecting anywhere
 * at that x-time is still over the trace (off-scale signals remain hoverable,
 * a design choice mirroring the scope's visual clipping behavior — an
 * off-scale trace is rendered pinned to the edge and the user should always
 * be able to investigate it).
 */
const verticalDistanceToTrace = (
  sampleY: number,
  pointerY: number,
  height: number,
): number =>
  isSampleOffCanvas(sampleY, height) ? 0 : Math.abs(sampleY - pointerY);

/** Whether the pointer lies inside the canvas rectangle. */
const isPointerInsideCanvas = (pointer: PointerPosition): boolean =>
  pointer.x >= 0 &&
  pointer.x <= pointer.width &&
  pointer.y >= 0 &&
  pointer.y <= pointer.height;

// ---------------------------------------------------------------------------
// Sample-at-cursor — honest-signal lookup for the trace value at the
// cursor-time. Returns the value of the latest sample whose time is at-or-
// before `cursorTime`, mirroring scopeProjection's `sampleAt` semantics so
// hit-test and trace projection stay consistent (see IC-S15).
// ---------------------------------------------------------------------------

/** Value of the latest sample at-or-before `cursorTime`, or `null` when no such sample exists. */
const valueAtCursorTime = (
  trace: FrameTrace,
  cursorTime: number,
): number | null => {
  if (trace.samples.length === 0) return null;
  let latestValue: number | null = null;
  let latestTime = Number.NEGATIVE_INFINITY;
  for (const sample of trace.samples) {
    if (sample.t <= cursorTime && sample.t >= latestTime) {
      latestTime = sample.t;
      latestValue = sample.v;
    }
  }
  // Fallback: if every sample is strictly after cursorTime, snap to the
  // earliest sample (the pointer is to the left of the first observation).
  if (latestValue === null) {
    let earliest = trace.samples[0];
    for (const sample of trace.samples) {
      if (sample.t < earliest.t) earliest = sample;
    }
    latestValue = earliest.v;
  }
  return latestValue;
};

// ---------------------------------------------------------------------------
// Candidate selection — internal record used during the scan
// ---------------------------------------------------------------------------

interface Candidate {
  readonly trace: FrameTrace;
  readonly cursorTime: number;
  readonly cursorValue: number;
  readonly displayX: number;
  readonly displayY: number;
  readonly verticalDistance: number;
}

/**
 * Build a hit-test candidate for a single trace at the cursor-time, or
 * `null` when the trace has no samples.
 *
 * The reported `cursorValue` is the trace's value at the cursor-time
 * (honest-signal lookup — last sample at-or-before cursorTime); the
 * reported `displayX` is the pointer's x (the sample is "at" the pointer's
 * column, not the sample's own column), because the value lookup behaves
 * like a step function across the cursor's timeline.
 */
const candidateForTrace = (
  trace: FrameTrace,
  pointer: PointerPosition,
  frame: Frame,
  cursorTime: number,
): Candidate | null => {
  const cursorValue = valueAtCursorTime(trace, cursorTime);
  if (cursorValue === null) return null;
  const displayX = timeToX(cursorTime, pointer.width, frame.now);
  const displayY = valueToY(cursorValue, pointer.height, frame.yMax);
  const verticalDistance = verticalDistanceToTrace(
    displayY,
    pointer.y,
    pointer.height,
  );
  return {
    trace,
    cursorTime,
    cursorValue,
    displayX,
    displayY,
    verticalDistance,
  };
};

/** Convert the winning candidate into a HoverSelection. */
const toHoverSelection = (
  candidate: Candidate,
  now: number,
): HoverSelection => ({
  sessionId: candidate.trace.sessionId,
  color: candidate.trace.color,
  value: candidate.cursorValue,
  time: candidate.cursorTime,
  ageMs: Math.max(0, now - candidate.cursorTime),
  displayX: candidate.displayX,
  displayY: candidate.displayY,
});

// ---------------------------------------------------------------------------
// scopeHitTest — the driving port
// ---------------------------------------------------------------------------

/**
 * Pure hit-test. Deterministic in (pointer, frame).
 *
 * Returns the HoverSelection for the trace whose sample nearest the pointer's
 * cursor-time has the minimum vertical distance to the pointer, provided
 * that distance is ≤ HOVER_SNAP_DISTANCE_PX. Off-canvas samples (values
 * above yMax or negative) are considered clipped to the canvas edge — a
 * pointer inside the canvas at that x-time is effectively on the clipped
 * trace, so off-scale signals remain hoverable.
 *
 * Returns `null` when:
 *   - the pointer is outside `[0, width] x [0, height]`
 *   - the frame has no traces
 *   - no trace has any samples
 *   - the nearest on-canvas trace is beyond the snap radius
 */
export const scopeHitTest = (
  pointer: PointerPosition,
  frame: Frame,
): HoverSelection | null => {
  if (!isPointerInsideCanvas(pointer)) return null;
  const cursorTime = xToTime(pointer.x, pointer.width, frame.now);
  let winner: Candidate | null = null;
  for (const trace of frame.traces) {
    const candidate = candidateForTrace(trace, pointer, frame, cursorTime);
    if (candidate === null) continue;
    if (winner === null || candidate.verticalDistance < winner.verticalDistance) {
      winner = candidate;
    }
  }
  if (winner === null) return null;
  if (winner.verticalDistance > HOVER_SNAP_DISTANCE_PX) return null;
  return toHoverSelection(winner, frame.now);
};

/**
 * Unit tests: scopeHitTest — pure hit-test over a projected Frame.
 *
 * Behaviors (drives later M4-S2/4/5/6):
 *   1. within-snap:   pointer within HOVER_SNAP_DISTANCE_PX vertical of the
 *                     trace sample at the cursor-time returns a HoverSelection
 *                     identifying that trace.
 *   2. beyond-snap:   pointer outside HOVER_SNAP_DISTANCE_PX vertically
 *                     from every on-canvas trace sample returns null.
 *   3. outside-bounds: pointer x/y outside [0,width]/[0,height] returns null.
 *   4. empty-frame:   frame with no traces returns null regardless of pointer.
 *   5. nearest-of-two: when two traces' samples are within snap, selection
 *                      picks the vertically-closer one.
 *
 * Geometry contract (match the canvas coordinate system used by the scope):
 *   - timeToX(t, width, now) = width * (1 - (now - t) / WINDOW_MS)
 *     (older-left, newer-right; the newest sample sits at x = width)
 *   - valueToY(v, height, yMax) = height * (1 - v / yMax)
 *     (low-value-bottom, high-value-top; canvas origin is top-left)
 *
 * Snap semantics: vertical distance only. The cursor-time is derived from
 * pointer.x and each trace's sample-at-cursor-time determines the trace's
 * y at the pointer's column. Off-canvas sample y positions clip to the
 * nearest canvas edge for distance measurement (off-scale signals remain
 * hoverable — a design choice mirroring the scope's visual clipping).
 *
 * Pure: no imports from `react`, `adapters`, `views`, `window`, `document`,
 * or `domain/oscilloscope`. The function only inspects the Frame structure.
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";

import { HOVER_SNAP_DISTANCE_PX, scopeHitTest } from "./scopeHitTest";
import type { Frame } from "./scopeProjection";
import {
  METRICS,
  SESSION_COLORS,
  WINDOW_MS,
  type RateSample,
} from "./phosphorMetricConfig";

const NOW = 1_000_000_000;

// ---------------------------------------------------------------------------
// Frame construction helpers — avoid depending on buildFrame so hit-test
// unit tests remain narrow and decoupled from projection behavior.
// ---------------------------------------------------------------------------

const timeToX = (t: number, width: number, now: number): number =>
  width * (1 - (now - t) / WINDOW_MS);

const valueToY = (v: number, height: number, yMax: number): number =>
  height * (1 - v / yMax);

const buildTestFrame = (
  traceSpecs: ReadonlyArray<{
    readonly sessionId: string;
    readonly color: string;
    readonly samples: ReadonlyArray<RateSample>;
  }>,
): Frame => {
  const traces = traceSpecs.map((spec) => ({
    sessionId: spec.sessionId,
    color: spec.color,
    samples: spec.samples,
    latestValue:
      spec.samples.length === 0 ? null : spec.samples[spec.samples.length - 1].v,
  }));
  return {
    now: NOW,
    metric: "events",
    yMax: METRICS.events.yMax,
    unit: METRICS.events.unit,
    traces,
    pulses: [],
    legend: traces.map((t) => ({
      sessionId: t.sessionId,
      color: t.color,
      latestValue: t.latestValue,
    })),
  };
};

// ---------------------------------------------------------------------------
// Case 1: within-snap — pointer near a trace sample returns a HoverSelection
// ---------------------------------------------------------------------------

describe("scopeHitTest — within snap distance", () => {
  it("returns a HoverSelection when pointer is exactly on the sample", () => {
    const width = 1000;
    const height = 400;
    const sampleTime = NOW - 1500; // 1.5 seconds ago
    const sampleValue = 10;
    const frame = buildTestFrame([
      {
        sessionId: "session-1",
        color: SESSION_COLORS[0],
        samples: [{ t: sampleTime, v: sampleValue }],
      },
    ]);

    const x = timeToX(sampleTime, width, NOW);
    const y = valueToY(sampleValue, height, METRICS.events.yMax);

    const selection = scopeHitTest({ x, y, width, height }, frame);

    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("session-1");
    expect(selection?.color).toBe(SESSION_COLORS[0]);
    expect(selection?.value).toBe(sampleValue);
    expect(selection?.time).toBe(sampleTime);
    expect(selection?.ageMs).toBeCloseTo(1500, 3);
    expect(selection?.displayX).toBeCloseTo(x, 3);
    expect(selection?.displayY).toBeCloseTo(y, 3);
  });

  it("returns a HoverSelection when pointer is vertically within HOVER_SNAP_DISTANCE_PX", () => {
    const width = 1000;
    const height = 400;
    const sampleTime = NOW - 2000;
    const sampleValue = 8;
    const frame = buildTestFrame([
      {
        sessionId: "session-a",
        color: SESSION_COLORS[0],
        samples: [{ t: sampleTime, v: sampleValue }],
      },
    ]);

    const sampleX = timeToX(sampleTime, width, NOW);
    const sampleY = valueToY(sampleValue, height, METRICS.events.yMax);
    // Pointer vertically 20px below the sample — within the 28px snap radius.
    const selection = scopeHitTest(
      { x: sampleX, y: sampleY + 20, width, height },
      frame,
    );

    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("session-a");
    expect(selection?.value).toBe(sampleValue);
  });

  it("includes off-canvas (above yMax) traces — they clip to the top edge and remain hoverable", () => {
    // WS-4 shape: value > yMax → displayY < 0. The trace clips to the top
    // edge (y=0) and a pointer inside the canvas at that x-time is within
    // snap vertically only if it is within HOVER_SNAP_DISTANCE_PX of y=0.
    const width = 1000;
    const height = 400;
    const sampleTime = NOW - 1500;
    const offScaleValue = 47; // > events yMax of 15
    const frame = buildTestFrame([
      {
        sessionId: "focused",
        color: SESSION_COLORS[1],
        samples: [{ t: sampleTime, v: offScaleValue }],
      },
    ]);

    // Pointer near the top edge — clipped trace is at y=0, snap holds.
    const x = timeToX(sampleTime, width, NOW);
    const selection = scopeHitTest({ x, y: 10, width, height }, frame);

    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("focused");
    expect(selection?.value).toBe(offScaleValue);
  });
});

// ---------------------------------------------------------------------------
// Case 2: beyond-snap — pointer too far from every trace returns null
// ---------------------------------------------------------------------------

describe("scopeHitTest — beyond snap distance", () => {
  it("returns null when the pointer is vertically farther than HOVER_SNAP_DISTANCE_PX from the trace", () => {
    const width = 1000;
    const height = 400;
    const sampleTime = NOW - 1000;
    const sampleValue = 2;
    const frame = buildTestFrame([
      {
        sessionId: "session-1",
        color: SESSION_COLORS[0],
        samples: [{ t: sampleTime, v: sampleValue }],
      },
    ]);

    const sampleY = valueToY(sampleValue, height, METRICS.events.yMax);
    const sampleX = timeToX(sampleTime, width, NOW);
    // 100px vertical offset — well outside the 28px snap radius.
    const selection = scopeHitTest(
      { x: sampleX, y: sampleY - 100, width, height },
      frame,
    );

    expect(selection).toBeNull();
  });

  it("property: pointer vertically farther than HOVER_SNAP_DISTANCE_PX from an on-scale trace returns null", () => {
    fc.assert(
      fc.property(
        fc.integer({ min: 200, max: 2000 }), // width
        fc.integer({ min: 200, max: 800 }), // height
        fc.integer({ min: 40, max: 500 }), // vertical offset beyond snap
        (width, height, offsetPx) => {
          // On-scale sample: value well within [0, yMax].
          const yMax = METRICS.events.yMax;
          const midValue = yMax / 2;
          const frame = buildTestFrame([
            {
              sessionId: "s1",
              color: SESSION_COLORS[0],
              samples: [{ t: NOW - 5000, v: midValue }],
            },
          ]);
          const sampleX = timeToX(NOW - 5000, width, NOW);
          const sampleY = valueToY(midValue, height, yMax);
          // Place pointer vertically offset — choose direction that keeps it
          // inside the canvas.
          const directions = [sampleY - offsetPx, sampleY + offsetPx].filter(
            (py) => py >= 0 && py <= height,
          );
          for (const py of directions) {
            const selection = scopeHitTest(
              { x: sampleX, y: py, width, height },
              frame,
            );
            expect(selection).toBeNull();
          }
        },
      ),
      { numRuns: 100 },
    );
  });
});

// ---------------------------------------------------------------------------
// Case 3: outside-bounds — pointer outside the canvas returns null
// ---------------------------------------------------------------------------

describe("scopeHitTest — pointer outside canvas bounds", () => {
  // Fixture-helper: construct a frame whose sample would produce a valid
  // selection if the pointer were inside the canvas. This makes the
  // "returns null" assertion contingent specifically on the out-of-bounds
  // guard, so mutating any of the four conjuncts in isPointerInsideCanvas
  // yields a detectable difference (null vs. valid selection).
  const width = 1000;
  const height = 400;
  const yMax = METRICS.events.yMax;
  const sampleTime = NOW - 10_000;
  // Pick a sample value so that the trace's displayY lies near the pointer's
  // y when the pointer is clamped into the canvas — this guarantees the
  // "inside" case would return a selection, not null.
  const sampleValue = yMax / 2;
  const frameWithSelectableTrace = buildTestFrame([
    {
      sessionId: "selectable",
      color: SESSION_COLORS[0],
      samples: [{ t: sampleTime, v: sampleValue }],
    },
  ]);
  const sampleX = timeToX(sampleTime, width, NOW);
  const sampleY = valueToY(sampleValue, height, yMax);

  it("returns null when pointer x is negative (and the inside-case would select)", () => {
    const selection = scopeHitTest(
      { x: -5, y: sampleY, width, height },
      frameWithSelectableTrace,
    );
    expect(selection).toBeNull();
  });

  it("returns null when pointer x exceeds width (and the inside-case would select)", () => {
    const selection = scopeHitTest(
      { x: width + 1, y: sampleY, width, height },
      frameWithSelectableTrace,
    );
    expect(selection).toBeNull();
  });

  it("returns null when pointer y is negative (and the inside-case would select)", () => {
    const selection = scopeHitTest(
      { x: sampleX, y: -1, width, height },
      frameWithSelectableTrace,
    );
    expect(selection).toBeNull();
  });

  it("returns null when pointer y exceeds height (and the inside-case would select)", () => {
    const selection = scopeHitTest(
      { x: sampleX, y: height + 1, width, height },
      frameWithSelectableTrace,
    );
    expect(selection).toBeNull();
  });

  it("control: pointer at (sampleX, sampleY) inside canvas returns the selectable trace", () => {
    // Sanity check that the above fixture really would select when inside —
    // this is the symmetric counterexample that converts the isPointerInsideCanvas
    // conjunct mutants from "survive" to "kill" by disagreeing with the
    // out-of-bounds null-return on the same fixture.
    const selection = scopeHitTest(
      { x: sampleX, y: sampleY, width, height },
      frameWithSelectableTrace,
    );
    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("selectable");
  });
});

// ---------------------------------------------------------------------------
// Case 4: empty-frame — no traces means no hover selection ever
// ---------------------------------------------------------------------------

describe("scopeHitTest — empty frame", () => {
  it("returns null when frame has zero traces", () => {
    const frame = buildTestFrame([]);
    const selection = scopeHitTest(
      { x: 500, y: 200, width: 1000, height: 400 },
      frame,
    );
    expect(selection).toBeNull();
  });

  it("returns null when all traces have zero samples", () => {
    const frame = buildTestFrame([
      { sessionId: "s1", color: SESSION_COLORS[0], samples: [] },
      { sessionId: "s2", color: SESSION_COLORS[1], samples: [] },
    ]);
    const selection = scopeHitTest(
      { x: 500, y: 200, width: 1000, height: 400 },
      frame,
    );
    expect(selection).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// Case 5: nearest-of-two — when multiple traces are within snap, pick nearest
// ---------------------------------------------------------------------------

describe("scopeHitTest — nearest of two candidates", () => {
  it("selects the trace whose sample is vertically closer to the pointer", () => {
    const width = 1000;
    const height = 400;
    const yMax = METRICS.events.yMax;
    const sampleTime = NOW - 10000;

    // Two on-scale traces at the same x but different values.
    const valueA = 2;
    const valueB = 10;
    const frame = buildTestFrame([
      {
        sessionId: "session-A",
        color: SESSION_COLORS[0],
        samples: [{ t: sampleTime, v: valueA }],
      },
      {
        sessionId: "session-B",
        color: SESSION_COLORS[1],
        samples: [{ t: sampleTime, v: valueB }],
      },
    ]);

    const x = timeToX(sampleTime, width, NOW);
    const yB = valueToY(valueB, height, yMax);
    // Pointer very close to trace-B's sample — should select session-B.
    const selection = scopeHitTest({ x, y: yB + 3, width, height }, frame);

    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("session-B");
    expect(selection?.value).toBe(valueB);
  });

  it("does not select a trace whose sample is beyond snap when a closer trace is within snap", () => {
    const width = 1000;
    const height = 400;
    const yMax = METRICS.events.yMax;
    const sampleTime = NOW - 10000;

    // Trace A sits at pointer y; trace B sits 200px below — beyond snap.
    const pointerY = valueToY(5, height, yMax);
    const frame = buildTestFrame([
      {
        sessionId: "close",
        color: SESSION_COLORS[0],
        samples: [{ t: sampleTime, v: 5 }],
      },
      {
        sessionId: "far",
        color: SESSION_COLORS[1],
        samples: [{ t: sampleTime, v: 5 - (200 * yMax) / height }],
      },
    ]);

    const x = timeToX(sampleTime, width, NOW);
    const selection = scopeHitTest({ x, y: pointerY, width, height }, frame);

    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("close");
  });
});

// ---------------------------------------------------------------------------
// Case 6: canvas-edge boundary — pointer exactly at (0,y), (width,y),
// (x,0), (x,height) is INSIDE the canvas per the inclusive-edge contract.
// This exercises the four `>=` / `<=` conjuncts in isPointerInsideCanvas.
// ---------------------------------------------------------------------------

describe("scopeHitTest — pointer exactly on canvas edges (inclusive)", () => {
  const width = 1000;
  const height = 400;
  const yMax = METRICS.events.yMax;
  // Centered sample so any edge-pointer we place is close enough vertically.
  const sampleValue = yMax / 2;
  const sampleTime = NOW - 30_000; // middle of the window
  const frame = buildTestFrame([
    {
      sessionId: "edge-session",
      color: SESSION_COLORS[0],
      samples: [{ t: sampleTime, v: sampleValue }],
    },
  ]);
  const sampleY = valueToY(sampleValue, height, yMax);

  it("returns a selection when pointer.x === 0 (left edge inclusive)", () => {
    const selection = scopeHitTest({ x: 0, y: sampleY, width, height }, frame);
    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("edge-session");
  });

  it("returns a selection when pointer.x === width (right edge inclusive)", () => {
    const selection = scopeHitTest({ x: width, y: sampleY, width, height }, frame);
    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("edge-session");
  });

  it("returns a selection when pointer.y === 0 (top edge inclusive) and a trace is near top", () => {
    // Place the sample near the top so y=0 is within snap distance vertically.
    const topSampleValue = yMax - 0.1; // nearly at top
    const topFrame = buildTestFrame([
      {
        sessionId: "top-session",
        color: SESSION_COLORS[0],
        samples: [{ t: sampleTime, v: topSampleValue }],
      },
    ]);
    const x = timeToX(sampleTime, width, NOW);
    const selection = scopeHitTest({ x, y: 0, width, height }, topFrame);
    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("top-session");
  });

  it("returns a selection when pointer.y === height (bottom edge inclusive) and a trace is near bottom", () => {
    // Place the sample near the bottom so y=height is within snap distance.
    const bottomSampleValue = 0.1; // nearly at bottom
    const bottomFrame = buildTestFrame([
      {
        sessionId: "bottom-session",
        color: SESSION_COLORS[0],
        samples: [{ t: sampleTime, v: bottomSampleValue }],
      },
    ]);
    const x = timeToX(sampleTime, width, NOW);
    const selection = scopeHitTest({ x, y: height, width, height }, bottomFrame);
    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("bottom-session");
  });
});

// ---------------------------------------------------------------------------
// Case 7: sample-on-edge — sample at y=0 (top) or y=height (bottom) is
// considered ON the canvas per the STRICT `< 0` / `> height` off-canvas
// test. A pointer somewhere else at that x must compute vertical distance
// from the sample position (not treat the sample as clipped).
// ---------------------------------------------------------------------------

describe("scopeHitTest — sample exactly on canvas edge is not off-canvas", () => {
  const width = 1000;
  const height = 400;
  const yMax = METRICS.events.yMax;

  it("sample at v=yMax (displayY === 0) is on-canvas: pointer at y=200 is beyond snap", () => {
    // displayY for v=yMax is exactly 0 (top edge). The off-canvas test is
    // STRICT (`sampleY < 0`), so the sample is on-canvas and vertical
    // distance is |0 - 200| = 200 — far beyond the 28px snap radius.
    const sampleTime = NOW - 5000;
    const frame = buildTestFrame([
      {
        sessionId: "on-top-edge",
        color: SESSION_COLORS[0],
        samples: [{ t: sampleTime, v: yMax }],
      },
    ]);
    const x = timeToX(sampleTime, width, NOW);
    const selection = scopeHitTest({ x, y: 200, width, height }, frame);
    expect(selection).toBeNull();
  });

  it("sample at v=0 (displayY === height) is on-canvas: pointer at y=0 is beyond snap", () => {
    // displayY for v=0 is exactly `height` (bottom edge). The off-canvas
    // test is STRICT (`sampleY > height`), so the sample is on-canvas and
    // vertical distance is `height` — far beyond the 28px snap radius.
    const sampleTime = NOW - 5000;
    const frame = buildTestFrame([
      {
        sessionId: "on-bottom-edge",
        color: SESSION_COLORS[0],
        samples: [{ t: sampleTime, v: 0 }],
      },
    ]);
    const x = timeToX(sampleTime, width, NOW);
    const selection = scopeHitTest({ x, y: 0, width, height }, frame);
    expect(selection).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// Case 8: sample-at-exact-cursor-time — valueAtCursorTime uses the
// inclusive `sample.t <= cursorTime` predicate. A sample whose time is
// exactly equal to the cursor time must be selected (not skipped).
// ---------------------------------------------------------------------------

describe("scopeHitTest — sample time equals cursor time", () => {
  it("selects the sample whose time exactly equals the cursor time (inclusive <=)", () => {
    const width = 1000;
    const height = 400;
    const yMax = METRICS.events.yMax;
    // Pick a sample time, put the pointer at exactly the same x-column so
    // the derived cursor time equals the sample's time.
    const exactTime = NOW - 15_000;
    const sampleValue = yMax / 3;
    const frame = buildTestFrame([
      {
        sessionId: "exact",
        color: SESSION_COLORS[0],
        samples: [{ t: exactTime, v: sampleValue }],
      },
    ]);
    const x = timeToX(exactTime, width, NOW);
    const y = valueToY(sampleValue, height, yMax);

    const selection = scopeHitTest({ x, y, width, height }, frame);
    expect(selection).not.toBeNull();
    expect(selection?.value).toBe(sampleValue);
    expect(selection?.time).toBe(exactTime);
  });

  it("selects the earliest sample when cursor time is strictly before every sample", () => {
    // Fallback path: every sample.t > cursorTime. valueAtCursorTime returns
    // the earliest sample's value. The resulting selection is on-canvas and
    // should be reported.
    const width = 1000;
    const height = 400;
    const yMax = METRICS.events.yMax;
    const earliestTime = NOW - 10_000;
    const earliestValue = yMax / 4;
    const frame = buildTestFrame([
      {
        sessionId: "falling-back",
        color: SESSION_COLORS[0],
        samples: [
          { t: earliestTime, v: earliestValue },
          { t: NOW - 5000, v: yMax / 2 },
        ],
      },
    ]);
    // Pointer at the left edge — cursorTime corresponds to NOW - WINDOW_MS,
    // which is strictly before earliestTime (earliestTime = NOW - 10_000,
    // cursorTime = NOW - 60_000). The selection.time is the cursor time
    // (step-function semantics), but the reported value is the earliest
    // sample's value — that's the fallback-earliest contract under test.
    const yOfEarliest = valueToY(earliestValue, height, yMax);
    const selection = scopeHitTest({ x: 0, y: yOfEarliest, width, height }, frame);
    expect(selection).not.toBeNull();
    expect(selection?.value).toBe(earliestValue);
    expect(selection?.sessionId).toBe("falling-back");
  });
});

// ---------------------------------------------------------------------------
// Case 9: snap-distance boundary — `verticalDistance > HOVER_SNAP_DISTANCE_PX`
// returns null; `verticalDistance === HOVER_SNAP_DISTANCE_PX` returns a
// selection (boundary is inclusive of the snap radius).
// ---------------------------------------------------------------------------

describe("scopeHitTest — snap distance boundary", () => {
  const width = 1000;
  const height = 400;
  const yMax = METRICS.events.yMax;
  const sampleTime = NOW - 10_000;
  const sampleValue = yMax / 2;
  const frame = buildTestFrame([
    {
      sessionId: "snap-boundary",
      color: SESSION_COLORS[0],
      samples: [{ t: sampleTime, v: sampleValue }],
    },
  ]);
  const x = timeToX(sampleTime, width, NOW);
  const sampleY = valueToY(sampleValue, height, yMax);

  it("returns a selection when vertical distance equals HOVER_SNAP_DISTANCE_PX (inclusive boundary)", () => {
    const selection = scopeHitTest(
      { x, y: sampleY + HOVER_SNAP_DISTANCE_PX, width, height },
      frame,
    );
    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("snap-boundary");
  });

  it("returns null when vertical distance is just beyond HOVER_SNAP_DISTANCE_PX", () => {
    const selection = scopeHitTest(
      { x, y: sampleY + HOVER_SNAP_DISTANCE_PX + 1, width, height },
      frame,
    );
    expect(selection).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// Case 9b: sample-time strictly greater than cursor — a sample whose time
// is AFTER the cursor must be ignored in the main loop (it's looking for
// sample.t <= cursorTime). The fallback then chooses the earliest. This
// kills the `sample.t < cursorTime` / `sample.t <= cursorTime` equality
// flip on line 133.
// ---------------------------------------------------------------------------

describe("scopeHitTest — sample time strictly after cursor vs. equal-to cursor", () => {
  it("returns value of earliest sample when ALL samples are strictly after cursor time", () => {
    const width = 1000;
    const height = 400;
    const yMax = METRICS.events.yMax;
    // Two samples, both AFTER cursor (pointer at x=0 → cursorTime = NOW-60_000).
    const valueA = yMax / 5;
    const valueB = yMax / 2;
    const frame = buildTestFrame([
      {
        sessionId: "after-only",
        color: SESSION_COLORS[0],
        samples: [
          { t: NOW - 1000, v: valueA },
          { t: NOW - 500, v: valueB }, // strictly later than earliest
        ],
      },
    ]);
    // Fallback-earliest: sample.t < earliest.t chooses valueA (t=NOW-1000).
    // If the mutator flips to `<=`, the iteration order still yields valueA
    // first (NOW-1000) and then valueB (NOW-500 is not <= NOW-1000), so
    // earliest stays valueA. We need a scenario where `<` vs. `<=` matters.
    // Place pointer at the earliest sample's y so we can confirm value.
    const yOfValueA = valueToY(valueA, height, yMax);
    const selection = scopeHitTest({ x: 0, y: yOfValueA, width, height }, frame);
    expect(selection).not.toBeNull();
    expect(selection?.value).toBe(valueA);
    expect(selection?.sessionId).toBe("after-only");
  });

  it("fallback-earliest chooses the sample with the strictly smallest time when duplicates exist", () => {
    // To exercise `sample.t < earliest.t` vs. `<=`: make two samples share
    // the minimum time. Whichever is seen first is kept by `<`; `<=` would
    // overwrite to the second. Because samples share t, their values must
    // also match to keep the test behavior-observable. We therefore use a
    // single-time sample array with a distinct LATER sample — the earliest
    // is unique, and the loop body picks it on the first iteration. The
    // `<` → `<=` flip is still detectable because in the alt case the
    // loop would replace earliest with the later sample incorrectly (the
    // later sample's .t > earliest.t, so neither `<` nor `<=` is true).
    // Concretely: construct samples [earliest, later]. With `<`, earliest
    // stays. With `<=`, earliest stays. So this test won't distinguish.
    //
    // Key insight: the mutator `< → <=` only affects behavior when
    // sample.t === earliest.t. That requires duplicate timestamps with
    // DIFFERENT values — which the scope tolerates via an "append in order"
    // contract. We emulate that here.
    const width = 1000;
    const height = 400;
    const yMax = METRICS.events.yMax;
    const sharedTime = NOW - 1000;
    const firstValue = yMax / 4;
    const duplicateTimeValue = yMax / 3; // different value, same timestamp
    const frame = buildTestFrame([
      {
        sessionId: "duplicate-time",
        color: SESSION_COLORS[0],
        samples: [
          { t: sharedTime, v: firstValue },
          { t: sharedTime, v: duplicateTimeValue },
        ],
      },
    ]);
    // Pointer at x=0 → cursor time ≪ sharedTime. Fallback-earliest picks
    // the first-seen minimum. With `<`, the first sample (firstValue) wins.
    // With `<=`, the second overwrites (duplicateTimeValue wins).
    const yOfFirst = valueToY(firstValue, height, yMax);
    const selection = scopeHitTest({ x: 0, y: yOfFirst, width, height }, frame);
    expect(selection).not.toBeNull();
    expect(selection?.value).toBe(firstValue);
  });
});

// ---------------------------------------------------------------------------
// Case 9c: mixed traces (empty + populated) — the empty trace must be
// skipped (candidateForTrace returns null → outer loop continues). Kills
// the line-180 `if (cursorValue === null) return null;` guard and the
// line-241 `if (candidate === null) continue;` guard by exposing the
// populated trace's selection as the winner.
// ---------------------------------------------------------------------------

describe("scopeHitTest — mixed empty and populated traces", () => {
  it("skips the empty trace and selects the populated one", () => {
    const width = 1000;
    const height = 400;
    const yMax = METRICS.events.yMax;
    const sampleTime = NOW - 10_000;
    const sampleValue = yMax / 2;
    const frame = buildTestFrame([
      // First trace is empty — candidateForTrace should return null and
      // the outer loop should `continue` past it.
      { sessionId: "empty", color: SESSION_COLORS[0], samples: [] },
      // Second trace has a sample — should be selected.
      {
        sessionId: "populated",
        color: SESSION_COLORS[1],
        samples: [{ t: sampleTime, v: sampleValue }],
      },
    ]);
    const x = timeToX(sampleTime, width, NOW);
    const y = valueToY(sampleValue, height, yMax);
    const selection = scopeHitTest({ x, y, width, height }, frame);
    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("populated");
  });

  it("returns null when the only populated trace is beyond snap distance", () => {
    // Negative control: empty + populated-but-far trace. The empty trace
    // must still be skipped (not crash), and the far trace must produce
    // null because of snap, not because of the empty-guard.
    const width = 1000;
    const height = 400;
    const yMax = METRICS.events.yMax;
    const sampleTime = NOW - 10_000;
    const farSampleValue = yMax / 2;
    const frame = buildTestFrame([
      { sessionId: "empty", color: SESSION_COLORS[0], samples: [] },
      {
        sessionId: "far",
        color: SESSION_COLORS[1],
        samples: [{ t: sampleTime, v: farSampleValue }],
      },
    ]);
    const x = timeToX(sampleTime, width, NOW);
    const y = valueToY(farSampleValue, height, yMax);
    // Pointer 200px above the far sample — well beyond snap.
    const selection = scopeHitTest({ x, y: y - 200, width, height }, frame);
    expect(selection).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// Case 10: off-canvas sample below baseline — `sampleY > height`. Mirrors
// the existing "above top" case and exercises the second disjunct of
// isSampleOffCanvas.
// ---------------------------------------------------------------------------

describe("scopeHitTest — off-canvas samples below baseline", () => {
  it("selects a trace whose sample is below baseline (clipped to bottom edge)", () => {
    const width = 1000;
    const height = 400;
    const sampleTime = NOW - 1500;
    const negativeValue = -3; // < 0 → displayY > height → off-canvas
    const frame = buildTestFrame([
      {
        sessionId: "below-baseline",
        color: SESSION_COLORS[1],
        samples: [{ t: sampleTime, v: negativeValue }],
      },
    ]);
    // Pointer anywhere inside the canvas at the sample's x-time should
    // select this trace: off-canvas samples clip to the edge and verticalDistance = 0.
    const x = timeToX(sampleTime, width, NOW);
    const selection = scopeHitTest({ x, y: height - 10, width, height }, frame);
    expect(selection).not.toBeNull();
    expect(selection?.sessionId).toBe("below-baseline");
    expect(selection?.value).toBe(negativeValue);
  });
});

// ---------------------------------------------------------------------------
// HOVER_SNAP_DISTANCE_PX export — constant exposed for downstream config
// ---------------------------------------------------------------------------

describe("scopeHitTest — exported constants", () => {
  it("exports HOVER_SNAP_DISTANCE_PX = 28", () => {
    expect(HOVER_SNAP_DISTANCE_PX).toBe(28);
  });
});

tests/acceptance/norbert-performance-mon.source:
/**
 * Acceptance tests: Performance Monitor v2 Phosphor Scope — Integration Checkpoints.
 *
 * These checkpoints exercise the derivation seam (hookProcessor helpers that
 * convert hook and OTel events into rate samples and pulses) and the store
 * seam (multiSessionStore's public append and query contract). They prove
 * the upstream event stream correctly lands in the store, and the store
 * preserves the temporal contracts the scope depends on.
 *
 * Driving ports (DELIVER wave will implement):
 *   - multiSessionStore.addSession / removeSession / appendRateSample /
 *     appendPulse / getRateHistory / getPulses / getSessionIds / subscribe
 *   - hookProcessor derivation helpers: deriveEventsRate, deriveTokensRate,
 *     deriveToolCallsRate, emitPulse
 *   - buildFrame(store, metric, now) -> Frame  (for property-shaped scenarios)
 *
 * Feature file: integration-checkpoints.feature
 *
 * Traces to: US-PM-001 (amended), v2-phosphor-architecture.md §4 Q1
 * (derivation pipeline), ADR-049 (per-metric rate buffers + pulse log).
 *
 * Property-shaped scenarios use fast-check (added as dev-dep during DELIVER).
 */

import { describe, it, expect } from "vitest";
import fc from "fast-check";

import {
  NOW,
  PULSE_LIFETIME_MS,
  PULSE_STRENGTHS,
  RATE_TICK_MS,
  WINDOW_MS,
  type MetricId,
  type PulseKind,
} from "./fixtures";

// Driving ports (resolved as DELIVER wave lands modules).
import { createMultiSessionStore } from "../../../../src/plugins/norbert-usage/adapters/multiSessionStore";
import {
  deriveEventsRate,
  deriveTokensRate,
  deriveToolCallsRate,
  emitPulse,
} from "../../../../src/plugins/norbert-usage/hookProcessor";
import { buildFrame } from "../../../../src/plugins/norbert-usage/domain/phosphor/scopeProjection";
import { scopeHitTest } from "../../../../src/plugins/norbert-usage/domain/phosphor/scopeHitTest";
import { decayFactor } from "../../../../src/plugins/norbert-usage/domain/phosphor/pulseTiming";

/**
 * Derivation helpers — signatures target the hookProcessor shape. Each returns
 * the derived RateSample (or pulse) for a single tick/event, without mutating
 * store state. The caller appends. `deriveEventsRate`, `deriveTokensRate`,
 * `deriveToolCallsRate`, and `emitPulse` are imported from the real module
 * (delivered in steps 08-01 / 08-02 / 08-03 / 08-04); the remaining helpers
 * stay `declare`d until their respective IC scenarios are un-skipped.
 */

// ---------------------------------------------------------------------------
// IC-S1: A 5-second tick of hook arrivals derives an events-per-second sample
// Tag: @driving_port @US-PM-001
// First scenario of this file — must fail for a BUSINESS-logic reason.
// ---------------------------------------------------------------------------

describe("IC-S1: A 5-second tick of hook arrivals derives an events-per-second sample", () => {
  it("15 events over 5 seconds yields a sample of 3 at the tick boundary", () => {
    // Given 15 hook events arrive for session-1 across a 5-second tick
    const eventCount = 15;
    const windowMs = RATE_TICK_MS;
    const tickBoundary = NOW;

    // When the events-per-second derivation runs for that tick
    const sample = deriveEventsRate(eventCount, windowMs, tickBoundary);

    // Then the sample is 3 evt/s timestamped at the tick boundary
    expect(sample.v).toBeCloseTo(3, 5);
    expect(sample.t).toBe(tickBoundary);
  });
});

// ---------------------------------------------------------------------------
// IC-S2: An OTel api-request event derives a tokens-per-second sample
// Tag: @driving_port @US-PM-001
// ---------------------------------------------------------------------------

describe("IC-S2: An OTel api-request event derives a tokens-per-second sample", () => {
  it("500 tokens over 2 seconds yields a sample of 250", () => {
    // Given an OTel api-request event with 500 tokens and 2-second duration
    const totalTokens = 500;
    const durationMs = 2000;
    const t = NOW;

    // When the tokens-per-second derivation runs for that event
    const sample = deriveTokensRate(totalTokens, durationMs, t);

    // Then a sample of 250 tok/s is produced
    expect(sample.v).toBeCloseTo(250, 5);
    expect(sample.t).toBe(t);
  });
});

// ---------------------------------------------------------------------------
// IC-S3: Tool-call events within a 5-second tick derive a tool-calls-per-second sample
// Tag: @driving_port @US-PM-001
// ---------------------------------------------------------------------------

describe("IC-S3: Tool-call events within a 5-second tick derive a tool-calls-per-second sample", () => {
  it("10 tool calls over 5 seconds yields a sample of 2", () => {
    // Given 10 tool-call events arrive across a 5-second tick
    const sample = deriveToolCallsRate(10, RATE_TICK_MS, NOW);

    // Then the sample is 2 calls/s at the tick boundary
    expect(sample.v).toBeCloseTo(2, 5);
    expect(sample.t).toBe(NOW);
  });
});

// ---------------------------------------------------------------------------
// IC-S4: A tool-use hook event emits a pulse at the event's timestamp
// Tag: @driving_port @US-PM-001
// ---------------------------------------------------------------------------

describe("IC-S4: A tool-use hook event emits a pulse at the event's timestamp", () => {
  it("pulse kind is tool and t matches the event time", () => {
    const eventTime = NOW - 500;
    const pulse = emitPulse("tool", eventTime);

    expect(pulse.kind).toBe("tool");
    expect(pulse.t).toBe(eventTime);
    expect(pulse.strength).toBe(PULSE_STRENGTHS.tool);
  });
});

// ---------------------------------------------------------------------------
// IC-S5: A lifecycle hook event emits a pulse with a smaller strength than a tool-use pulse
// Tag: @driving_port @US-PM-001
// ---------------------------------------------------------------------------

describe("IC-S5: A lifecycle hook event emits a pulse with a smaller strength than a tool-use pulse", () => {
  it("tool-use pulse strength exceeds lifecycle pulse strength", () => {
    const toolPulse = emitPulse("tool", NOW);
    const lifecyclePulse = emitPulse("lifecycle", NOW);

    expect(toolPulse.strength).toBeGreaterThan(lifecyclePulse.strength);
    expect(toolPulse.strength).toBe(PULSE_STRENGTHS.tool);
    expect(lifecyclePulse.strength).toBe(PULSE_STRENGTHS.lifecycle);
  });
});

// ---------------------------------------------------------------------------
// IC-S6: Appending rate samples preserves temporal order on read
// Tag: @driving_port @US-PM-001
// ---------------------------------------------------------------------------

describe("IC-S6: Appending rate samples preserves temporal order on read", () => {
  it("samples read back in oldest-to-newest order", () => {
    // Given rate samples at 10, 20, 30 seconds ago, appended in that order
    const store = createMultiSessionStore();
    store.addSession("session-1");
    store.appendRateSample("session-1", "events", NOW - 30_000, 2);
    store.appendRateSample("session-1", "events", NOW - 20_000, 4);
    store.appendRateSample("session-1", "events", NOW - 10_000, 6);

    // When the store is queried
    const history = store.getRateHistory("session-1", "events");

    // Then the samples are ordered oldest to newest
    expect(history).toHaveLength(3);
    for (let i = 1; i < history.length; i++) {
      expect(history[i].t).toBeGreaterThan(history[i - 1].t);
    }
  });
});

// ---------------------------------------------------------------------------
// IC-S7: Appending pulses preserves arrival order on read
// Tag: @driving_port @US-PM-001
// ---------------------------------------------------------------------------

describe("IC-S7: Appending pulses preserves arrival order on read", () => {
  it("pulses read back in the arrival order they were appended", () => {
    // Given pulses at 4, 2, and 1 seconds ago appended in that order
    const store = createMultiSessionStore();
    store.addSession("session-1");
    const arrivals = [4000, 2000, 1000];
    for (const ageMs of arrivals) {
      store.appendPulse("session-1", {
        t: NOW - ageMs,
        kind: "tool",
        strength: PULSE_STRENGTHS.tool,
      });
    }

    // When the store is queried (logical clock so retention trim aligns with NOW)
    const pulses = store.getPulses("session-1", NOW);

    // Then the pulses are returned in arrival order
    expect(pulses).toHaveLength(3);
    for (let i = 1; i < pulses.length; i++) {
      // Since appended at decreasing ages (newer each time), timestamps are increasing.
      expect(pulses[i].t).toBeGreaterThan(pulses[i - 1].t);
    }
  });
});

// ---------------------------------------------------------------------------
// IC-S8: Querying a non-existent session returns empty history and pulses
// Tag: @driving_port @US-PM-001
// ---------------------------------------------------------------------------

describe("IC-S8: Querying a non-existent session returns empty history and pulses", () => {
  it("returns empty collections for a never-added session id", () => {
    const store = createMultiSessionStore();

    expect(store.getRateHistory("session-ghost", "events")).toHaveLength(0);
    expect(store.getPulses("session-ghost")).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// IC-S9: Subscribers are notified after appendRateSample
// Tag: @driving_port @US-PM-001
// ---------------------------------------------------------------------------

describe("IC-S9: Subscribers are notified after appendRateSample", () => {
  it("subscriber callback is invoked exactly once", () => {
    const store = createMultiSessionStore();
    store.addSession("session-1");

    let notifications = 0;
    const unsubscribe = store.subscribe(() => {
      notifications += 1;
    });
    notifications = 0; // reset after any setup-time notification

    store.appendRateSample("session-1", "events", NOW, 5);
    expect(notifications).toBe(1);

    unsubscribe();
  });
});

// ---------------------------------------------------------------------------
// IC-S10: Subscribers are notified after appendPulse
// Tag: @driving_port @US-PM-001
// ---------------------------------------------------------------------------

describe("IC-S10: Subscribers are notified after appendPulse", () => {
  it("subscriber callback is invoked exactly once", () => {
    const store = createMultiSessionStore();
    store.addSession("session-1");

    let notifications = 0;
    const unsubscribe = store.subscribe(() => {
      notifications += 1;
    });
    notifications = 0;

    store.appendPulse("session-1", {
      t: NOW,
      kind: "tool",
      strength: PULSE_STRENGTHS.tool,
    });
    expect(notifications).toBe(1);

    unsubscribe();
  });
});

// ---------------------------------------------------------------------------
// IC-S10b: Subscribers are notified after addSession and removeSession
// Tag: @driving_port @US-PM-001
// ADR-049 Contract A: lifecycle notifies via the same pub/sub.
// NOTE: No counter reset between the two lifecycle calls — the exactly-once
// invariant per call is what we are contracting. A reset would hide double
// notifies on the second call.
// ---------------------------------------------------------------------------

describe("IC-S10b: Subscribers are notified after addSession and removeSession", () => {
  it("addSession notifies once and removeSession notifies once — two total", () => {
    const store = createMultiSessionStore();

    let notifications = 0;
    const unsubscribe = store.subscribe(() => {
      notifications += 1;
    });

    store.addSession("session-1");
    expect(notifications).toBe(1);

    store.removeSession("session-1");
    expect(notifications).toBe(2);

    unsubscribe();
  });
});

// ---------------------------------------------------------------------------
// IC-S11: @property Frame values never invent sub-interval spikes beyond
//         bracketing arrived values
// Tag: @driving_port @property @US-PM-001
//
// Generators:
//   - sessionId: non-empty string
//   - metric: one of the three MetricIds
//   - arrived-samples: a non-empty array of (ageMsFromNow, v) pairs strictly
//     inside the 60s window, monotonically increasing in timestamp (i.e.
//     decreasing ageMs). Values are positive finite doubles.
//   - nowOffset: integer offset around a fixed logical NOW for variety
//
// Invariant: for every projected trace sample, locate its two bracketing
// arrived samples (the arrived pair (left, right) with left.t <= sample.t
// <= right.t; or a single arrived sample when the projected sample lies at
// an endpoint). The projected sample.v must fall within
// [min(left.v, right.v), max(left.v, right.v)] — i.e. no invented
// sub-interval spike above the higher or below the lower bracketing value.
// ---------------------------------------------------------------------------

describe("IC-S11 @property: Frame values never invent sub-interval spikes beyond bracketing arrived values", () => {
  it("every projected trace value is bounded by its two bracketing arrived samples", () => {
    const metricArb: fc.Arbitrary<MetricId> = fc.constantFrom<MetricId>(
      "events",
      "tokens",
      "toolcalls",
    );

    // A non-empty, timestamp-sorted sequence of arrived samples inside the
    // 60s window. We generate unique `ageMs` in [0, WINDOW_MS - 1] then sort
    // descending so the resulting `t = now - ageMs` sequence is ascending.
    const arrivedArb = fc
      .uniqueArray(fc.integer({ min: 0, max: WINDOW_MS - 1 }), {
        minLength: 1,
        maxLength: 12,
      })
      .chain((ages) => {
        const sortedAgesDesc = [...ages].sort((a, b) => b - a);
        return fc
          .array(fc.double({ min: 0, max: 1000, noNaN: true, noDefaultInfinity: true }), {
            minLength: sortedAgesDesc.length,
            maxLength: sortedAgesDesc.length,
          })
          .map((values) =>
            sortedAgesDesc.map((ageMs, i) => ({ ageMs, v: values[i] })),
          );
      });

    fc.assert(
      fc.property(
        fc.string({ minLength: 1, maxLength: 12 }),
        metricArb,
        arrivedArb,
        fc.integer({ min: -1000, max: 1000 }),
        (sessionId, metric, arrived, nowOffset) => {
          const now = NOW + nowOffset;
          const store = createMultiSessionStore();
          store.addSession(sessionId);
          for (const s of arrived) {
            store.appendRateSample(sessionId, metric, now - s.ageMs, s.v);
          }

          const frame = buildFrame(store, metric, now);
          const trace = frame.traces.find((t) => t.sessionId === sessionId);
          expect(trace).toBeDefined();

          // Bracketing lookup over arrived samples (ascending timestamp).
          const sortedArrived = arrived
            .map((s) => ({ t: now - s.ageMs, v: s.v }))
            .sort((a, b) => a.t - b.t);

          for (const sample of trace!.samples) {
            let left = sortedArrived[0];
            let right = sortedArrived[sortedArrived.length - 1];
            if (sample.t <= sortedArrived[0].t) {
              left = sortedArrived[0];
              right = sortedArrived[0];
            } else if (sample.t >= sortedArrived[sortedArrived.length - 1].t) {
              left = sortedArrived[sortedArrived.length - 1];
              right = sortedArrived[sortedArrived.length - 1];
            } else {
              for (let i = 0; i < sortedArrived.length - 1; i++) {
                if (
                  sortedArrived[i].t <= sample.t &&
                  sample.t <= sortedArrived[i + 1].t
                ) {
                  left = sortedArrived[i];
                  right = sortedArrived[i + 1];
                  break;
                }
              }
            }
            const hi = Math.max(left.v, right.v);
            const lo = Math.min(left.v, right.v);
            expect(sample.v).toBeLessThanOrEqual(hi + 1e-9);
            expect(sample.v).toBeGreaterThanOrEqual(lo - 1e-9);
          }
        },
      ),
    );
  });
});

